import React from "react";

const About = () => {
  return (
    <section
      id="about-section"            // <-- header's About button should scroll to this id
      style={{
        maxWidth: 1100,
        margin: "40px auto",
        padding: "30px 28px",
        borderRadius: 12,
        background: "#fff",
        boxShadow: "0 10px 30px rgba(0,0,0,0.08)",
        textAlign: "center",
      }}
    >
      <h2 style={{ margin: 0, fontSize: 28, color: "#0b63d6" }}>About Us</h2>
      <p style={{ marginTop: 12, color: "#6b7280", lineHeight: 1.6 }}>
        HEALink connects people to reliable healthcare services — book pathology,
        find blood banks, and access teleconsultations quickly. Our mission is
        to make healthcare accessible and simple.
      </p>
      {/* optional small CTA */}
      <div style={{ marginTop: 18 }}>
        <button
          onClick={() => window.scrollTo({ top: 0, behavior: "smooth" })}
          style={{
            padding: "10px 18px",
            borderRadius: 8,
            border: "none",
            background: "#0b63d6",
            color: "#fff",
            cursor: "pointer",
          }}
        >
          Back to top
        </button>
      </div>
    </section>
  );
};

export default About;
